+fn get_module() -> &'static mut GlobalModuleState {
+    let cell = &MODULE;
+    if cell.get().is_none() {
+        *cell.get() = Some(GlobalModuleState::new());
+    }
+    cell.get().as_mut().unwrap()
+}
